PATCH_SRC = '\n_MSTARMIE, _MFROSLASS = 1031, 861\n_STARYU, _SNORUNT = 1030, 860\n_DECK_MEGA = (_MSTARMIE in my_deck) or (_MFROSLASS in my_deck)\n_CRUSTLE, _DWEBBLE = 345, 344\ndef _mega_is_wall(self):\n    return any(p is not None and p.id in (_CRUSTLE, _DWEBBLE) for p in self._opponent_board())\n_MEGA_TO_HAND_PRI = {_STARYU: 320, _SNORUNT: 300, _MSTARMIE: 290, _MFROSLASS: 270, 3: 240, 1145: 200, 1182: 175, 1229: 150, 1119: 140}\ndef _mega_score_to_hand(self, card):\n    pid = card.id\n    s = _MEGA_TO_HAND_PRI.get(pid, 100) - self.hand_counts[pid] * 50\n    if pid == _MSTARMIE and self.field_counts[_STARYU] == 0 and self.hand_counts[_STARYU] == 0: s -= 160\n    if pid == _MFROSLASS and self.field_counts[_SNORUNT] == 0 and self.hand_counts[_SNORUNT] == 0: s -= 160\n    return s\n_orig_score_to_hand = LucarioPolicy._score_to_hand\ndef _disp_score_to_hand(self, card):\n    return _mega_score_to_hand(self, card) if _DECK_MEGA else _orig_score_to_hand(self, card)\nLucarioPolicy._score_to_hand = _disp_score_to_hand\ndef _mega_energy_target_score(self, pokemon, active):\n    pid = pokemon.id\n    if pid not in (_MSTARMIE, _MFROSLASS, _STARYU, _SNORUNT): return _orig_ets(self, pokemon, active)\n    ec = len(pokemon.energies); score = 8000 + (10 if active else 0); wall = _mega_is_wall(self)\n    if pid == _MSTARMIE:\n        if ec < 3:\n            score += 200 + ec * 80\n            if wall: score += 150\n        else: score -= 300\n        if active: score += 40\n    elif pid == _MFROSLASS:\n        if wall: score -= 200\n        elif ec < 1: score += 120\n        elif ec < 3: score += 50\n        else: score -= 120\n    else: score -= 60\n    return score\n_orig_ets = LucarioPolicy._energy_target_score\ndef _disp_energy_target_score(self, pokemon, active):\n    return _mega_energy_target_score(self, pokemon, active) if _DECK_MEGA else _orig_ets(self, pokemon, active)\nLucarioPolicy._energy_target_score = _disp_energy_target_score\n'
